import React, { useState, useRef } from 'react';
import { motion } from 'framer-motion';
import Sidebar from '../../components/Sidebar';
import Navbar from '../../components/Navbar';
import axios from 'axios';
import toast from 'react-hot-toast';
import { FiPlus, FiTrash2, FiSend, FiUploadCloud, FiX, FiCheck } from 'react-icons/fi';

const API = 'http://localhost:5000/api';

const CreateExam = () => {
  const [examData, setExamData] = useState({
    title: '', description: '', subject: '', duration: 60,
    totalMarks: 0, startTime: '', endTime: '', batch: '', course: ''
  });
  const [questions, setQuestions] = useState([{
    question: '', options: [
      { text: '', isCorrect: true },
      { text: '', isCorrect: false },
      { text: '', isCorrect: false },
      { text: '', isCorrect: false }
    ], marks: 1, image: null
  }]);
  const [pdfFile, setPdfFile] = useState(null);
  const [examImage, setExamImage] = useState(null);
  const [loading, setLoading] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const pdfRef = useRef();
  const examImageRef = useRef();
  const questionImageRefs = useRef({});

  // Validation function
  const validateFile = (file, type) => {
    const maxSize = 10 * 1024 * 1024; // 10MB
    if (file.size > maxSize) {
      toast.error(`File size exceeds 10MB limit`);
      return false;
    }

    if (type === 'pdf' && file.type !== 'application/pdf') {
      toast.error('Please upload a valid PDF file');
      return false;
    }

    if (type === 'image' && !['image/jpeg', 'image/png', 'image/jpg'].includes(file.type)) {
      toast.error('Only JPG and PNG images are allowed');
      return false;
    }

    return true;
  };

  const handleExamChange = (e) => {
    setExamData({ ...examData, [e.target.name]: e.target.value });
  };

  const handleQuestionChange = (index, field, value) => {
    const updated = [...questions];
    updated[index][field] = value;
    setQuestions(updated);
  };

  const handleOptionChange = (qIndex, oIndex, value) => {
    const updated = [...questions];
    updated[qIndex].options[oIndex].text = value;
    setQuestions(updated);
  };

  const handleCorrectAnswer = (qIndex, oIndex) => {
    const updated = [...questions];
    updated[qIndex].options = updated[qIndex].options.map((opt, i) => ({
      ...opt, isCorrect: i === oIndex
    }));
    setQuestions(updated);
  };

  // Exam Image Upload
  const handleExamImageUpload = (e) => {
    const file = e.target.files[0];
    if (file && validateFile(file, 'image')) {
      setExamImage(file);
      toast.success('Exam image uploaded successfully');
    }
    e.target.value = ''; // Reset input
  };

  // PDF Upload
  const handlePdfUpload = (e) => {
    const file = e.target.files[0];
    if (file && validateFile(file, 'pdf')) {
      setPdfFile(file);
      toast.success('PDF uploaded successfully');
    }
    e.target.value = ''; // Reset input
  };

  // Question Image Upload
  const handleQuestionImageUpload = (qIndex, e) => {
    const file = e.target.files[0];
    if (file && validateFile(file, 'image')) {
      const updated = [...questions];
      updated[qIndex].image = file;
      setQuestions(updated);
      toast.success('Question image uploaded');
    }
    e.target.value = ''; // Reset input
  };

  const removeExamImage = () => {
    setExamImage(null);
    if (examImageRef.current) examImageRef.current.value = '';
  };

  const removePdf = () => {
    setPdfFile(null);
    if (pdfRef.current) pdfRef.current.value = '';
  };

  const removeQuestionImage = (qIndex) => {
    const updated = [...questions];
    updated[qIndex].image = null;
    setQuestions(updated);
    if (questionImageRefs.current[qIndex]) {
      questionImageRefs.current[qIndex].value = '';
    }
  };

  const addQuestion = () => {
    setQuestions([...questions, {
      question: '', options: [
        { text: '', isCorrect: true },
        { text: '', isCorrect: false },
        { text: '', isCorrect: false },
        { text: '', isCorrect: false }
      ], marks: 1, image: null
    }]);
  };

  const removeQuestion = (index) => {
    if (questions.length > 1) {
      setQuestions(questions.filter((_, i) => i !== index));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    // Validation
    if (!examData.title.trim()) {
      toast.error('Please enter exam title');
      return;
    }
    if (!examData.subject.trim()) {
      toast.error('Please enter subject');
      return;
    }
    if (!examData.startTime || !examData.endTime) {
      toast.error('Please set start and end time');
      return;
    }

    const totalMarks = questions.reduce((sum, q) => sum + Number(q.marks), 0);

    setLoading(true);
    try {
      const formData = new FormData();
      
      // Add exam data
      Object.keys(examData).forEach(key => {
        if (key !== 'totalMarks') formData.append(key, examData[key]);
      });
      formData.append('totalMarks', totalMarks);
      
      // Add exam image
      if (examImage) formData.append('examImage', examImage);
      
      // Add PDF
      if (pdfFile) formData.append('pdfFile', pdfFile);

      // Add questions with their images
      const questionsToSend = questions.map(q => ({
        question: q.question,
        options: q.options,
        marks: Number(q.marks)
      }));
      formData.append('questions', JSON.stringify(questionsToSend));

      // Add question images separately
      questions.forEach((q, idx) => {
        if (q.image) {
          formData.append(`questionImage_${idx}`, q.image);
        }
      });

      const response = await axios.post(`${API}/exams`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });

      toast.success('Exam created successfully!');
      
      // Reset form
      setExamData({
        title: '', description: '', subject: '', duration: 60,
        totalMarks: 0, startTime: '', endTime: '', batch: '', course: ''
      });
      setQuestions([{
        question: '', options: [
          { text: '', isCorrect: true },
          { text: '', isCorrect: false },
          { text: '', isCorrect: false },
          { text: '', isCorrect: false }
        ], marks: 1, image: null
      }]);
      setExamImage(null);
      setPdfFile(null);
      
      // Clear file inputs
      if (examImageRef.current) examImageRef.current.value = '';
      if (pdfRef.current) pdfRef.current.value = '';
      Object.keys(questionImageRefs.current).forEach(key => {
        if (questionImageRefs.current[key]) questionImageRefs.current[key].value = '';
      });
      
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to create exam');
      console.error('Submit error:', error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="page-container">
      <Sidebar isOpen={isSidebarOpen} onClose={() => setIsSidebarOpen(false)} />
      <div className="main-content" style={{ paddingTop: '90px' }}>
        <Navbar onMenuToggle={(state) => setIsSidebarOpen(state)} />

        <motion.div className="page-header" initial={{ opacity: 0, y: -20 }} animate={{ opacity: 1, y: 0 }}>
          <h1>📝 Create Exam</h1>
          <p>Create MCQ-based exams with images and PDF support</p>
        </motion.div>

        <motion.div className="card" style={{ maxWidth: '900px' }} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}>
          <form onSubmit={handleSubmit}>
            {/* Basic Information */}
            <div style={{ marginBottom: '30px' }}>
              <h3 style={{ fontFamily: 'Poppins', marginBottom: '15px', fontSize: '1.2rem' }}>Basic Information</h3>
              
              <div className="form-group">
                <label className="form-label">Exam Title <span style={{ color: 'var(--danger)' }}>*</span></label>
                <input type="text" name="title" className="form-input" placeholder="e.g., JavaScript MCQ Test"
                  value={examData.title} onChange={handleExamChange} required />
              </div>

              <div className="form-group">
                <label className="form-label">Description</label>
                <textarea name="description" className="form-textarea" placeholder="Exam description..."
                  value={examData.description} onChange={handleExamChange} rows="3" />
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '15px' }}>
                <div className="form-group">
                  <label className="form-label">Subject <span style={{ color: 'var(--danger)' }}>*</span></label>
                  <input type="text" name="subject" className="form-input" placeholder="e.g., Mathematics"
                    value={examData.subject} onChange={handleExamChange} required />
                </div>
                <div className="form-group">
                  <label className="form-label">Duration (minutes)</label>
                  <input type="number" name="duration" className="form-input" min="10"
                    value={examData.duration} onChange={handleExamChange} required />
                </div>
                <div className="form-group">
                  <label className="form-label">Course</label>
                  <select name="course" className="form-select" value={examData.course} onChange={handleExamChange}>
                    <option value="">Select Course</option>
                    <option value="Web Development">Web Development</option>
                    <option value="App Development">App Development</option>
                    <option value="Python Programming">Python Programming</option>
                  </select>
                </div>
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '15px' }}>
                <div className="form-group">
                  <label className="form-label">Start Time <span style={{ color: 'var(--danger)' }}>*</span></label>
                  <input type="datetime-local" name="startTime" className="form-input"
                    value={examData.startTime} onChange={handleExamChange} required />
                </div>
                <div className="form-group">
                  <label className="form-label">End Time <span style={{ color: 'var(--danger)' }}>*</span></label>
                  <input type="datetime-local" name="endTime" className="form-input"
                    value={examData.endTime} onChange={handleExamChange} required />
                </div>
                <div className="form-group">
                  <label className="form-label">Batch</label>
                  <input type="text" name="batch" className="form-input" placeholder="e.g., Batch-2024"
                    value={examData.batch} onChange={handleExamChange} />
                </div>
              </div>
            </div>

            {/* Exam Media */}
            <div style={{ borderTop: '1px solid rgba(102,126,234,0.15)', paddingTop: '20px', marginBottom: '30px' }}>
              <h3 style={{ fontFamily: 'Poppins', marginBottom: '15px', fontSize: '1.2rem' }}>Exam Media</h3>
              
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
                {/* Exam Cover Image */}
                <div className="form-group">
                  <label className="form-label">Exam Cover Image (Optional)</label>
                  <div 
                    onClick={() => examImageRef.current.click()}
                    style={{
                      padding: '30px 20px',
                      border: '2px dashed rgba(102,126,234,0.3)',
                      borderRadius: '10px',
                      textAlign: 'center',
                      cursor: 'pointer',
                      transition: 'all 0.3s',
                      background: 'rgba(102,126,234,0.05)'
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.borderColor = 'var(--primary)';
                      e.currentTarget.style.background = 'rgba(102,126,234,0.1)';
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.borderColor = 'rgba(102,126,234,0.3)';
                      e.currentTarget.style.background = 'rgba(102,126,234,0.05)';
                    }}
                  >
                    <FiUploadCloud style={{ fontSize: '2rem', color: 'var(--primary)', marginBottom: '8px' }} />
                    <p style={{ fontSize: '0.9rem', color: 'var(--text-secondary)' }}>
                      JPG or PNG • Max 10MB
                    </p>
                  </div>
                  <input 
                    type="file" 
                    ref={examImageRef} 
                    style={{ display: 'none' }} 
                    accept=".jpg,.jpeg,.png"
                    onChange={handleExamImageUpload} 
                  />
                  {examImage && (
                    <motion.div 
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      style={{ marginTop: '10px', display: 'flex', alignItems: 'center', gap: '10px', padding: '10px', background: 'rgba(76,175,80,0.1)', borderRadius: '8px' }}
                    >
                      <FiCheck style={{ color: '#4CAF50' }} />
                      <span style={{ fontSize: '0.9rem' }}>{examImage.name}</span>
                      <button 
                        type="button" 
                        onClick={removeExamImage}
                        style={{ marginLeft: 'auto', background: 'none', border: 'none', cursor: 'pointer', color: 'var(--danger)' }}
                      >
                        <FiX />
                      </button>
                    </motion.div>
                  )}
                </div>

                {/* PDF Upload */}
                <div className="form-group">
                  <label className="form-label">Exam PDF (Optional)</label>
                  <div 
                    onClick={() => pdfRef.current.click()}
                    style={{
                      padding: '30px 20px',
                      border: '2px dashed rgba(102,126,234,0.3)',
                      borderRadius: '10px',
                      textAlign: 'center',
                      cursor: 'pointer',
                      transition: 'all 0.3s',
                      background: 'rgba(102,126,234,0.05)'
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.borderColor = 'var(--primary)';
                      e.currentTarget.style.background = 'rgba(102,126,234,0.1)';
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.borderColor = 'rgba(102,126,234,0.3)';
                      e.currentTarget.style.background = 'rgba(102,126,234,0.05)';
                    }}
                  >
                    <FiUploadCloud style={{ fontSize: '2rem', color: 'var(--primary)', marginBottom: '8px' }} />
                    <p style={{ fontSize: '0.9rem', color: 'var(--text-secondary)' }}>
                      PDF • Max 10MB
                    </p>
                  </div>
                  <input 
                    type="file" 
                    ref={pdfRef} 
                    style={{ display: 'none' }} 
                    accept=".pdf"
                    onChange={handlePdfUpload} 
                  />
                  {pdfFile && (
                    <motion.div 
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      style={{ marginTop: '10px', display: 'flex', alignItems: 'center', gap: '10px', padding: '10px', background: 'rgba(76,175,80,0.1)', borderRadius: '8px' }}
                    >
                      <FiCheck style={{ color: '#4CAF50' }} />
                      <span style={{ fontSize: '0.9rem' }}>{pdfFile.name}</span>
                      <button 
                        type="button" 
                        onClick={removePdf}
                        style={{ marginLeft: 'auto', background: 'none', border: 'none', cursor: 'pointer', color: 'var(--danger)' }}
                      >
                        <FiX />
                      </button>
                    </motion.div>
                  )}
                </div>
              </div>
            </div>

            {/* Questions */}
            <div style={{ borderTop: '1px solid rgba(102,126,234,0.15)', paddingTop: '20px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
                <h3 style={{ fontFamily: 'Poppins', fontSize: '1.2rem' }}>Questions ({questions.length})</h3>
                <span className="badge badge-primary">
                  Total Marks: {questions.reduce((sum, q) => sum + Number(q.marks), 0)}
                </span>
              </div>

              {questions.map((q, qIndex) => (
                <motion.div
                  key={qIndex}
                  style={{
                    background: 'rgba(102,126,234,0.05)',
                    border: '1px solid rgba(102,126,234,0.15)',
                    borderRadius: '14px',
                    padding: '20px',
                    marginBottom: '15px'
                  }}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: qIndex * 0.05 }}
                >
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '12px', alignItems: 'center' }}>
                    <span className="badge badge-primary">Question {qIndex + 1}</span>
                    <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                      <input 
                        type="number" 
                        className="form-input" 
                        style={{ width: '80px', padding: '6px 10px' }}
                        placeholder="Marks" 
                        value={q.marks}
                        onChange={(e) => handleQuestionChange(qIndex, 'marks', e.target.value)} 
                        min="1" 
                      />
                      {questions.length > 1 && (
                        <button 
                          type="button" 
                          className="btn btn-danger btn-sm" 
                          onClick={() => removeQuestion(qIndex)}
                          title="Delete question"
                        >
                          <FiTrash2 />
                        </button>
                      )}
                    </div>
                  </div>

                  {/* Question Text */}
                  <div className="form-group" style={{ marginBottom: '15px' }}>
                    <label className="form-label" style={{ fontSize: '0.85rem' }}>Question Text</label>
                    <input 
                      type="text" 
                      className="form-input" 
                      placeholder="Enter your question here..."
                      value={q.question}
                      onChange={(e) => handleQuestionChange(qIndex, 'question', e.target.value)} 
                      required 
                    />
                  </div>

                  {/* Question Image Upload */}
                  <div style={{ marginBottom: '15px' }}>
                    <label className="form-label" style={{ fontSize: '0.85rem' }}>Question Image (Optional)</label>
                    <div 
                      onClick={() => {
                        if (!questionImageRefs.current[qIndex]) {
                          questionImageRefs.current[qIndex] = React.createRef();
                        }
                        questionImageRefs.current[qIndex]?.click?.();
                      }}
                      style={{
                        padding: '15px',
                        border: '2px dashed rgba(102,126,234,0.3)',
                        borderRadius: '8px',
                        textAlign: 'center',
                        cursor: 'pointer',
                        transition: 'all 0.3s',
                        background: 'rgba(102,126,234,0.03)',
                        fontSize: '0.9rem'
                      }}
                      onMouseEnter={(e) => {
                        e.currentTarget.style.borderColor = 'var(--primary)';
                        e.currentTarget.style.background = 'rgba(102,126,234,0.08)';
                      }}
                      onMouseLeave={(e) => {
                        e.currentTarget.style.borderColor = 'rgba(102,126,234,0.3)';
                        e.currentTarget.style.background = 'rgba(102,126,234,0.03)';
                      }}
                    >
                      {q.image ? (
                        <span style={{ color: 'var(--success)' }}>✓ {q.image.name}</span>
                      ) : (
                        <span style={{ color: 'var(--text-secondary)' }}>Click to upload image</span>
                      )}
                    </div>
                    <input 
                      type="file" 
                      ref={(el) => questionImageRefs.current[qIndex] = el}
                      style={{ display: 'none' }} 
                      accept=".jpg,.jpeg,.png"
                      onChange={(e) => handleQuestionImageUpload(qIndex, e)} 
                    />
                    {q.image && (
                      <button 
                        type="button" 
                        onClick={() => removeQuestionImage(qIndex)}
                        style={{
                          marginTop: '8px',
                          padding: '4px 12px',
                          fontSize: '0.85rem',
                          color: 'var(--danger)',
                          background: 'none',
                          border: '1px solid var(--danger)',
                          borderRadius: '4px',
                          cursor: 'pointer'
                        }}
                      >
                        Remove Image
                      </button>
                    )}
                  </div>

                  {/* Options Grid */}
                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
                    {q.options.map((opt, oIndex) => (
                      <div key={oIndex} style={{ display: 'flex', gap: '10px', alignItems: 'flex-start' }}>
                        <input
                          type="radio"
                          name={`correct-${qIndex}`}
                          checked={opt.isCorrect}
                          onChange={() => handleCorrectAnswer(qIndex, oIndex)}
                          style={{ accentColor: 'var(--primary)', marginTop: '8px', cursor: 'pointer' }}
                          title="Mark as correct answer"
                        />
                        <div style={{ flex: 1 }}>
                          <input 
                            type="text" 
                            className="form-input" 
                            style={{ padding: '8px 12px', fontSize: '0.9rem' }}
                            placeholder={`Option ${oIndex + 1}`}
                            value={opt.text}
                            onChange={(e) => handleOptionChange(qIndex, oIndex, e.target.value)} 
                            required 
                          />
                          {opt.isCorrect && (
                            <p style={{ fontSize: '0.75rem', color: 'var(--success)', marginTop: '4px' }}>
                              ✓ Correct Answer
                            </p>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                </motion.div>
              ))}

              <motion.button
                type="button" 
                className="btn btn-outline btn-block"
                onClick={addQuestion}
                whileHover={{ scale: 1.02 }}
                style={{ marginBottom: '20px', marginTop: '15px' }}
              >
                <FiPlus /> Add Another Question
              </motion.button>
            </div>

            {/* Submit Button */}
            <motion.button
              type="submit" 
              className="btn btn-primary btn-block btn-lg"
              disabled={loading}
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
              style={{ marginTop: '20px' }}
            >
              {loading ? (
                <span style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                  <span>Creating Exam...</span>
                  <span style={{ animation: 'spin 1s linear infinite' }}>⏳</span>
                </span>
              ) : (
                <><FiSend /> Create Exam</>
              )}
            </motion.button>
          </form>
        </motion.div>
      </div>

      <style>{`
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
};

export default CreateExam;
